class ArraySlice {
private:
    Array& originalArray_;
    int fixed_x_, fixed_y_;
public:
    ArraySlice(Array& array, int x) : originalArray_(array), fixed_x_(x) {}
    ArraySlice(Array& array, int x, int y) : originalArray_(array), fixed_x_(x), fixed_y_(y) {}

    // Overloading for the second index, returning another ArraySlice
    ArraySlice operator[](int y) {
        if (fixed_y_ >= 0) {
            throw std::runtime_error("Already at the third dimension!");
        }
        return ArraySlice(originalArray_, fixed_x_, y);
    }

    // Final overload for the third index, allowing value setting
